// ShaderLab Custom — Orbital
uniform vec3 uColor;
uniform float uBright,uEdge;
varying float vBlink;
varying float vPhase;
void main(){
  vec3  col=uColor*uBright;
  float alpha=1.0;
  float d=0.0;
  // Disc base — siempre activo como fallback
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.25)discard;alpha=1.0-smoothstep(uEdge,0.25,d);}
  col=uColor*(1.20*(0.33+vBlink*0.060));
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.18)discard;if(0.15>0.005&&d<0.15)discard;alpha=1.0-smoothstep(0.090,0.18,d);}
  {float _pw=pow(clamp(vPhase,0.0,1.0),0.85);col*=mix(2.45,0.18,_pw);}
  if(alpha<=0.0)discard;
  gl_FragColor=vec4(col,clamp(alpha,0.0,1.0));
}
